 CREATE TABLE `meta_data2`.`device_mgt` ( `id` varchar(33) NOT NULL ,  `date` int(11) DEFAULT NULL ,  `type` varchar(100) DEFAULT NULL ,  `onboarded_type` varchar(100) DEFAULT NULL ,  `model` varchar(200) DEFAULT NULL ,  `status` varchar(100) DEFAULT NULL ,  `online_status` varchar(100) DEFAULT NULL ,  `training_id` varchar(100) DEFAULT NULL ,  `partner` varchar(100) DEFAULT NULL ,  `center` varchar(100) DEFAULT NULL ,  `api_user` varchar(100) DEFAULT NULL ,  `custodian` varchar(100) DEFAULT NULL ,  `country` varchar(100) DEFAULT NULL ,  `state` varchar(100) DEFAULT NULL ,  `lga` varchar(100) DEFAULT NULL ,  `ward` varchar(100) DEFAULT NULL ,  `purpose` text DEFAULT NULL ,  `serial_number` varchar(200) DEFAULT NULL ,  `storage` decimal(20,4) DEFAULT NULL ,  `os_name` varchar(200) DEFAULT NULL ,  `os_version` varchar(200) DEFAULT NULL ,  `app_version` varchar(200) DEFAULT NULL ,  `processor_speed` decimal(20,4) DEFAULT NULL ,  `avail_storage` decimal(20,4) DEFAULT NULL ,  `ram` decimal(20,4) DEFAULT NULL ,  `imsi` varchar(200) DEFAULT NULL ,  `imei` varchar(200) DEFAULT NULL ,  `network_strength` varchar(200) DEFAULT NULL ,  `network_type` varchar(200) DEFAULT NULL ,  `latitude` decimal(20,10) DEFAULT NULL ,  `longitude` decimal(20,10) DEFAULT NULL ,  `capture_time` int(11) DEFAULT NULL ,  `update_time` int(11) DEFAULT NULL ,  `battery` varchar(200) DEFAULT NULL ,  `camera` varchar(200) DEFAULT NULL ,  `screen_size` decimal(20,4) DEFAULT NULL ,  `screen_resolution` varchar(200) DEFAULT NULL ,  `architecture` varchar(200) DEFAULT NULL ,  `gps_module` varchar(200) DEFAULT NULL ,  `fingerprint` varchar(200) DEFAULT NULL ,  `otg` varchar(200) DEFAULT NULL ,  `printer` varchar(200) DEFAULT NULL ,  `country_pings` varchar(100) DEFAULT NULL ,  `state_pings` varchar(100) DEFAULT NULL ,  `lga_pings` varchar(100) DEFAULT NULL ,  `ward_pings` varchar(100) DEFAULT NULL ,  `data` mediumtext DEFAULT NULL , `serial_num` int(11) NOT NULL, `creator_role` varchar(100) DEFAULT NULL, `created_source` varchar(100) DEFAULT NULL, `created_by` varchar(100) DEFAULT NULL, `creation_date` int(11) DEFAULT NULL, `modified_source` varchar(100) DEFAULT NULL, `modified_by` varchar(100) DEFAULT NULL, `modification_date` int(11) DEFAULT NULL, `ip_address` varchar(100) DEFAULT NULL, `device_id` text NOT NULL, `record_status` varchar(2) DEFAULT NULL ) ENGINE=InnoDB DEFAULT CHARSET=latin1 ; 
ALTER TABLE `meta_data2`.`device_mgt` ADD PRIMARY KEY (`serial_num`), ADD UNIQUE KEY `id` (`id`) ; 
ALTER TABLE `meta_data2`.`device_mgt` MODIFY `serial_num` int(11) NOT NULL AUTO_INCREMENT ; 
ALTER TABLE `meta_data2`.`device_mgt`  ADD `workflow` varchar(200) DEFAULT NULL AFTER `ward_pings` ; 
ALTER TABLE `meta_data2`.`device_mgt`  ADD `dev_id` varchar(200) DEFAULT NULL AFTER `onboarded_type` ; 
ALTER TABLE `meta_data2`.`device_mgt`  DROP `model` ; 
ALTER TABLE `meta_data2`.`device_mgt`  ADD `fep_agent_nin` varchar(100) DEFAULT NULL AFTER `partner` ; 
ALTER TABLE `meta_data2`.`device_mgt`  ADD `model` varchar(200) DEFAULT NULL AFTER `dev_id` ; 
ALTER TABLE `meta_data2`.`device_mgt`  ADD `activation_date` int(11) DEFAULT NULL AFTER `purpose` ; 
ALTER TABLE `meta_data2`.`device_mgt`  ADD `status_msg` varchar(200) DEFAULT NULL AFTER `status` ,  ADD `increment` int(11) DEFAULT NULL AFTER `workflow` ; 
ALTER TABLE `meta_data2`.`device_mgt`  ADD `sub_status` varchar(100) DEFAULT NULL AFTER `status` ; 
